CREATE TRIGGER LG_STFICHE_UPD_123_01 ON LG_123_01_STFICHE
FOR UPDATE
AS
DECLARE @CLREF      INT
DECLARE @TRCODE     SMALLINT
DECLARE @NETTOTAL   FLOAT
DECLARE @REPORTRATE FLOAT
DECLARE @BILLED     SMALLINT
DECLARE @STATUS     SMALLINT
DECLARE @CANCELLED  SMALLINT
DECLARE @AFFECTCOLLTRL SMALLINT
DECLARE @AFFECTRISK SMALLINT
DECLARE @FROMORDWITHPAY SMALLINT
SELECT @CLREF = D.CLIENTREF,
       @TRCODE = D.TRCODE,
       @NETTOTAL = D.NETTOTAL,
       @REPORTRATE = D.REPORTRATE,
       @BILLED = D.BILLED,
       @STATUS = D.STATUS,
       @CANCELLED = D.CANCELLED,
       @AFFECTCOLLTRL = D.AFFECTCOLLATRL,
       @AFFECTRISK = D.AFFECTRISK,
       @FROMORDWITHPAY = D.FROMORDWITHPAY    FROM DELETED D
IF (ISNULL(@AFFECTRISK,0)=0) AND (ISNULL(@CANCELLED,0)=0) AND (ISNULL(@FROMORDWITHPAY,0)=0)
 EXECUTE LG_UPDATECLCARDRISKNUMS_123_01 @CLREF, @TRCODE, @NETTOTAL, -1, @REPORTRATE, @BILLED, 0, @STATUS, 0
IF (@AFFECTCOLLTRL=1) AND (ISNULL(@CANCELLED,0)=0)
 EXECUTE LG_UPDCOLLATRLRISK_123_01 @CLREF, @TRCODE, @NETTOTAL, -1, @REPORTRATE, @BILLED, 0, @STATUS, 0
SELECT @CLREF = I.CLIENTREF,
       @TRCODE = I.TRCODE,
       @NETTOTAL = I.NETTOTAL,
       @REPORTRATE = I.REPORTRATE,
       @BILLED = I.BILLED,
       @STATUS = I.STATUS,
       @CANCELLED = I.CANCELLED,
       @AFFECTCOLLTRL = I.AFFECTCOLLATRL,
       @AFFECTRISK = I.AFFECTRISK,
       @FROMORDWITHPAY = I.FROMORDWITHPAY   FROM INSERTED I
IF (ISNULL(@AFFECTRISK,0)=0) AND (ISNULL(@CANCELLED,0)=0) AND (ISNULL(@FROMORDWITHPAY,0)=0)
 EXECUTE LG_UPDATECLCARDRISKNUMS_123_01 @CLREF, @TRCODE, @NETTOTAL, 1, @REPORTRATE, @BILLED, 0, @STATUS, 0
IF (@AFFECTCOLLTRL=1) AND (ISNULL(@CANCELLED,0)=0)
 EXECUTE LG_UPDCOLLATRLRISK_123_01 @CLREF, @TRCODE, @NETTOTAL, 1, @REPORTRATE, @BILLED, 0, @STATUS, 0
